import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Limiting the buffer size to prevent buffer overflow
        int bufferSize = Math.min(userInput.length(), 10);
        byte[] buffer = new byte[bufferSize];

        // Copying user input to the buffer
        System.arraycopy(userInput.getBytes(), 0, buffer, 0, bufferSize);

        // Outputting the buffer contents securely
        System.out.println("Buffer contents: " + new String(buffer));
    }
}

